tinymce.PluginManager.add('popupimage', function(editor, url) {
    editor.ui.registry.addIcon('popupimage', '<?xml version="1.0" encoding="utf-8"?>\n' +
        '<!-- Generator: Adobe Illustrator 16.0.0, SVG Export Plug-In . SVG Version: 6.00 Build 0)  -->\n' +
        '<!DOCTYPE svg PUBLIC "-//W3C//DTD SVG 1.1//EN" "http://www.w3.org/Graphics/SVG/1.1/DTD/svg11.dtd">\n' +
        '<svg version="1.1" id="Layer_1" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" x="0px" y="0px"\n' +
        '\t width="14px" height="16px" viewBox="0 0 14 16" enable-background="new 0 0 14 16" xml:space="preserve">\n' +
        '<g>\n' +
        '\t<g>\n' +
        '\t\t<path fill-rule="evenodd" clip-rule="evenodd" d="M6,11h1v1h2V7H4v2h1v1H4v1H3v1H2v1H1v1H0v2h2v-1h1v-1h1v-1h1v-1h1V11z M0,0v10h2\n' +
        '\t\t\tV2h10v12H6v2h8V0H0z"/>\n' +
        '\t</g>\n' +
        '</g>\n' +
        '</svg>');

    var openDialog = function () {
        var cid = editor.getParam('content_id');
        var ctype = editor.getParam('content_type');
        var module_code = editor.getParam('module_code');
        var query = '?cid='+cid+'&ctype='+ctype+'&moduleCode='+module_code;
        return editor.windowManager.openUrl({
            url: tinymce.baseURL + '/plugins/popupimage/scripts/popup_image.php'+query,
            title: 'Popup Image',
            width: 800,
            height: 400,
        });
    };

    editor.ui.registry.addButton('popupimage', {
        tooltip: 'Popup Image',
        icon: 'popupimage',
        onAction: function () {
            // Open window
            openDialog();
        }

    });

    // Adds a menu item, which can then be included in any menu via the menu/menubar configuration
    editor.ui.registry.addMenuItem('popupimage', {
        text: 'Popup Image',
        icon: 'popupimage',
        onAction: function () {
            // Open window
            openDialog();
        }
    });
});